import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { listarEntregas, deletarEntrega } from "../../services/entregaService";
import ConfirmModal from "../../components/ConfirmModal";

function formatarData(dataStr) {
  if (!dataStr) return "—";
  const d = new Date(dataStr);
  return d.toLocaleDateString("pt-BR");
}

function BadgeStatus({ status }) {
  const map = {
    pendente:  { cls: "badge-pendente",  label: "Pendente",   icon: "clock" },
    em_transito: { cls: "badge-transito", label: "Em trânsito", icon: "arrow-right-circle" },
    entregue:  { cls: "badge-entregue",  label: "Entregue",   icon: "check-circle" },
    cancelado: { cls: "badge-cancelado", label: "Cancelado",  icon: "x-circle" },
  };
  const info = map[status] || { cls: "badge-pendente", label: status || "—", icon: "circle" };
  return (
    <span className={`badge-status ${info.cls}`}>
      <i className={`bi bi-${info.icon}`} />
      {info.label}
    </span>
  );
}

export default function EntregaList() {
  const [entregas, setEntregas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modalId, setModalId] = useState(null);
  const navigate = useNavigate();

  async function carregar() {
    try {
      setLoading(true);
      const res = await listarEntregas();
      setEntregas(res.data);
    } catch {
      toast.error("Erro ao carregar entregas.");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { carregar(); }, []);

  async function handleDelete() {
    try {
      await deletarEntrega(modalId);
      toast.success("Entrega removida com sucesso!");
      setModalId(null);
      carregar();
    } catch {
      toast.error("Erro ao remover entrega.");
      setModalId(null);
    }
  }

  return (
    <>
      {modalId && (
        <ConfirmModal
          message="Tem certeza que deseja excluir esta entrega? Esta ação não pode ser desfeita."
          onConfirm={handleDelete}
          onCancel={() => setModalId(null)}
        />
      )}

      <div className="card-custom">
        <div className="card-header-custom">
          <span className="card-header-title">
            <i className="bi bi-box-seam" />
            Entregas
          </span>
          <button
            className="btn-accent"
            onClick={() => navigate("/entregas/nova")}
          >
            <i className="bi bi-plus-lg" />
            Nova Entrega
          </button>
        </div>

        <div style={{ padding: "0 6px" }}>
          {loading ? (
            <div style={{ padding: "16px" }}>
              {[1, 2, 3, 4].map((n) => (
                <div key={n} className="shimmer-row" />
              ))}
            </div>
          ) : entregas.length === 0 ? (
            <div className="empty-state">
              <i className="bi bi-inbox" />
              <p>Nenhuma entrega cadastrada ainda.</p>
            </div>
          ) : (
            <div style={{ overflowX: "auto" }}>
              <table className="table-custom">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Remetente</th>
                    <th>Destinatário</th>
                    <th>Tipo</th>
                    <th>Postagem</th>
                    <th>Prev. Entrega</th>
                    <th>Status</th>
                    <th style={{ textAlign: "right" }}>Ações</th>
                  </tr>
                </thead>
                <tbody>
                  {entregas.map((e) => (
                    <tr key={e.id}>
                      <td style={{ color: "var(--text-muted)", width: 45 }}>
                        {e.id}
                      </td>
                      <td><strong>{e.nomeRemetente}</strong></td>
                      <td>{e.nomeDestinatario}</td>
                      <td>
                        {e.TipoEntregum?.descricao ||
                          e.TipoEntrega?.descricao ||
                          e.tipoEntregaId ||
                          "—"}
                      </td>
                      <td>{formatarData(e.dataPostagem)}</td>
                      <td>{formatarData(e.dataPrevistaEntrega)}</td>
                      <td>
                        <BadgeStatus status={e.status} />
                      </td>
                      <td style={{ textAlign: "right" }}>
                        <div
                          style={{
                            display: "flex",
                            gap: 6,
                            justifyContent: "flex-end",
                          }}
                        >
                          <button
                            className="btn-icon edit"
                            title="Editar"
                            onClick={() => navigate(`/entregas/editar/${e.id}`)}
                          >
                            <i className="bi bi-pencil" />
                          </button>
                          <button
                            className="btn-icon delete"
                            title="Excluir"
                            onClick={() => setModalId(e.id)}
                          >
                            <i className="bi bi-trash" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </>
  );
}
